mapper.select:
SELECT
,#{loanType} AS loanType FROM bps_78000.t_dktj_organization_loan_detail a LEFT JOIN public.t_sys_organization lno on lno.code = a.ln_org_code LEFT JOIN public.t_sys_organization blo on blo.code = a.belong_org_code
( lno.id = #{organizationId} OR lno.parent_ids @> CAST(ARRAY[#{organizationId}] AS INTEGER[]))
(blo.id = #{organizationId} OR blo.parent_ids @> CAST(ARRAY[#{organizationId}] AS INTEGER[]))
( (lno.id != #{organizationId} AND NOT lno.parent_ids @> CAST(ARRAY[#{organizationId}] AS INTEGER[])) AND (blo.id = #{organizationId} OR blo.parent_ids @> CAST(ARRAY[#{organizationId}] AS INTEGER[])) )
( (lno.id = #{organizationId} OR lno.parent_ids @> CAST(ARRAY[#{organizationId}] AS INTEGER[])) AND (blo.id != #{organizationId} AND NOT blo.parent_ids @> CAST(ARRAY[#{organizationId}] AS INTEGER[])) )
AND a.date >= #{startDate}
AND a.date <= #{endDate}
${sqlMap.dsf}
ORDER BY a.date DESC, a.five_class_flag ASC

